import requests

# Configuration for Kong Admin API
KONG_ADMIN_URL = "http://localhost:8001"

def create_service(name, url):
    service_data = {
        "name": name,
        "url": url
    }
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    return response.json()

def create_route(service_id, paths):
    route_data = {
        "paths": paths,
        "service": {"id": service_id}
    }
    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
    return response.json()

def create_upstream(name, targets):
    upstream_data = {
        "name": name,
        "targets": [{"target": target} for target in targets]
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    return response.json()

# Example usage
if __name__ == "__main__":
    # Create a service
    service_response = create_service("example-service", "http://example.com")
    print("Service created:", service_response)

    # Create a route for the service
    route_response = create_route(service_response["id"], ["/example-path"])
    print("Route created:", route_response)

    # Create an upstream with targets
    upstream_response = create_upstream("example-upstream", ["127.0.0.1:8080", "127.0.0.1:8081"])
    print("Upstream created:", upstream_response)